CivVAccess_Strings["TXT_KEY_CIVVACCESS_DIPLO_COL_ERA"] = "epoca"
CivVAccess_Strings["TXT_KEY_CIVVACCESS_DIPLO_COL_POLICIES"] = "politiche"
