CivVAccess_Strings["TXT_KEY_CIVVACCESS_DIPLO_INFLUENCE_TO_ALLIES"] = "{1_N} necessari per diventare alleati"
-- Allied-with cell variants. _ALLY_IS_YOU when we're the ally (no
